import Foundation

class AnalyticsDebugger {
    
    static let shared = AnalyticsDebugger()
    
    private init() {}
    
    func logUserInteraction(action: String, userId: String?) {
        guard let id = userId else { return }
        NSLog("User Interaction: \(action) | User ID: \(id)")
    }
    
    func logAuthenticationFlow(flow: String, userId: String?, email: String?) {
        if let id = userId, let mail = email {
            NSLog("Authentication Flow: \(flow) | User ID: \(id) | Email: \(mail)")
        }
    }
    
    func logAPICall(endpoint: String, method: String, requestPayload: Any?) {
        let payload = requestPayload != nil ? "\(requestPayload!)" : "N/A"
        NSLog("API Call: \(method) \(endpoint) | Request Payload: \(payload)")
    }
    
    func logAPIResponse(endpoint: String, responsePayload: Any?, duration: TimeInterval) {
        let payload = responsePayload != nil ? "\(responsePayload!)" : "N/A"
        NSLog("API Response: \(endpoint) | Response Payload: \(payload) | Duration: \(duration) seconds")
    }
    
    func logUserDataChange(userId: String?, changeDescription: String) {
        guard let id = userId else { return }
        NSLog("User Data Change: \(changeDescription) | User ID: \(id)")
    }
    
    func logErrorCondition(error: Error, additionalInfo: String?) {
        let info = additionalInfo != nil ? " | Info: \(additionalInfo!)" : ""
        NSLog("Error: \(error.localizedDescription)\(info)")
    }
    
    func logDebugMessage(_ message: String) {
        print("Debug: \(message)")
    }
}

